    pt: { title: "DAC7: o novo reporting de plataformas digitais em 2026", excerpt: "Quem vende em Amazon, Etsy, Airbnb, Vinted ou marketplaces europeus tem agora os rendimentos reportados à autoridade fiscal pela própria plataforma.", metaTitle: "DAC7 2026: reporting de plataformas digitais", metaDescription: "DAC7 obriga Amazon, Etsy, Airbnb a reportar os seus rendimentos desde 2024. Impacto na sua LLC e planeamento.", keywords: ["DAC7 plataformas digitais", "DAC7 Amazon Etsy Airbnb", "DAC7 vendedores online", "DAC7 reporting Fisco", "DAC7 LLC"] },
    ca: { title: "DAC7: el nou reporting de plataformes digitals el 2026", excerpt: "Si vens a Amazon, Etsy, Airbnb, Vinted o marketplaces europeus, els teus ingressos ja són reportats a Hisenda per la pròpia plataforma.", metaTitle: "DAC7 2026: reporting de plataformes digitals", metaDescription: "DAC7 obliga Amazon, Etsy, Airbnb a reportar els teus ingressos des de 2024. Impacte a la teva LLC.", keywords: ["DAC7 plataformes digitals", "DAC7 Amazon Etsy Airbnb", "DAC7 venedors online", "DAC7 reporting Hisenda", "DAC7 LLC"] },
